import{c as t,a0 as s,U as r,j as n,g as o,n as i,o as d,m as l}from"./chunks/framework.Dvkoa_vi.js";const v=JSON.parse('{"title":"Parte .NET Core 10 — Sesiones 3 a 5","description":"Fundamentos de .NET Core 10 para el curso de normalización (sesiones 3 a 5 del temario global).","frontmatter":{"title":"Parte .NET Core 10 — Sesiones 3 a 5","description":"Fundamentos de .NET Core 10 para el curso de normalización (sesiones 3 a 5 del temario global).","outline":"deep"},"headers":[],"relativePath":"02-dotnet/index.md","filePath":"02-dotnet/index.md"}'),c={name:"02-dotnet/index.md"};function u(p,e,m,b,g,h){const a=s("CopyOrDownloadAsMarkdownButtons");return r(),n("div",null,[e[0]||(e[0]=o("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/02-dotnet.md for this page in Markdown format",-1)),e[1]||(e[1]=o("h1",{id:"parte-net-core-10",tabindex:"-1"},[i("Parte .NET Core 10 "),o("a",{class:"header-anchor",href:"#parte-net-core-10","aria-label":"Permalink to “Parte .NET Core 10”"},"​")],-1)),d(a),e[2]||(e[2]=l('<p>Esta sección cubre las <strong>sesiones 6 a 8</strong> del curso, dedicadas a los fundamentos de .NET. Continúa tras la <a href="./../01-oracle/">Parte Oracle</a> y precede a la <a href="./../03-vue/">Parte Vue</a>.</p><h2 id="objetivos-del-modulo" tabindex="-1">Objetivos del módulo <a class="header-anchor" href="#objetivos-del-modulo" aria-label="Permalink to “Objetivos del módulo”">​</a></h2><div class="info custom-block"><p class="custom-block-title">CONTEXTO</p><p>Al finalizar este bloque, el alumno será capaz de:</p><ul><li>Entender la estructura de un proyecto ASP.NET Core 10 con la plantilla UA y arrancarlo localmente.</li><li>Distinguir <strong>entidad</strong> y <strong>DTO</strong> y aplicar la convención UA de &quot;varios DTOs por entidad&quot; (lectura, creación, actualización).</li><li>Implementar un controlador API REST con verbos HTTP, códigos de estado y <code>ProblemDetails</code>, y documentarlo bien para que aparezca correctamente en Scalar.</li><li>Probar sus endpoints sin tocar Vue, usando <strong>Chrome DevTools</strong> (pestaña Network) y la UI de <strong>Scalar</strong>.</li><li>Separar la lógica en capas (controlador delgado, servicio con <code>Result&lt;T&gt;</code>, acceso a Oracle).</li><li>Conectar con Oracle usando <strong>ClaseOracleBD3</strong> tanto para lectura (vistas) como para escritura (paquetes PL/SQL con OUT params).</li><li>Escribir su primer test xUnit &quot;simulado&quot; del controlador y un test &quot;real&quot; del servicio contra Oracle.</li></ul></div><h2 id="sesiones-de-este-bloque" tabindex="-1">Sesiones de este bloque <a class="header-anchor" href="#sesiones-de-este-bloque" aria-label="Permalink to “Sesiones de este bloque”">​</a></h2><table tabindex="0"><thead><tr><th>Sesión</th><th>Título</th><th>Duración</th></tr></thead><tbody><tr><td><a href="./sesiones/sesion-03-introduccion-dotnet/">Sesión 3: Introducción a .NET</a></td><td>Estructura del proyecto, <code>Program.cs</code>, inyección de dependencias, C# útil</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-04-dtos-apis/">Sesión 4: Modelos y primer API</a></td><td>DTOs, controladores API, verbos HTTP, códigos de estado, Scalar, probar sin BD desde Chrome</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-05-servicios-oracle/">Sesión 5: Servicios y acceso a Oracle</a></td><td>Capas, <code>Result&lt;T&gt;</code>/<code>HandleResult</code>, ClaseOracleBD3, llamada a paquetes PL/SQL, xUnit</td><td>1 h 30 min</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CONTINUACIÓN EN INTEGRACIÓN</p><p>Los temas de validación avanzada, gestión de errores global, DataTable y consumo desde Vue se cubren en las sesiones de <strong>Integración full-stack</strong> (sesiones 14-17), donde se ven de extremo a extremo:</p><table tabindex="0"><thead><tr><th>Sesión integración</th><th>Contenido .NET relacionado</th></tr></thead><tbody><tr><td><a href="./../04-integracion/sesiones/sesion-14-api-autenticacion/">Sesión 14: API y autenticación</a></td><td>OpenAPI, Scalar, claims, CAS+JWT cookies</td></tr><tr><td><a href="./../04-integracion/sesiones/sesion-15-validacion/">Sesión 15: Validación</a></td><td>DataAnnotations, FluentValidation, localización de mensajes</td></tr><tr><td><a href="./../04-integracion/sesiones/sesion-16-errores/">Sesión 16: Errores</a></td><td><code>Result&lt;T&gt;</code>, <code>ProblemDetails</code>, <code>IExceptionHandler</code>, toasts</td></tr><tr><td><a href="./../04-integracion/sesiones/sesion-17-datatable/">Sesión 17: DataTable</a></td><td>Paginación, filtros y ordenación en servidor</td></tr></tbody></table></div><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to “Requisitos previos”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><ul><li>Visual Studio 2022 con <strong>.NET 10 SDK</strong> instalado.</li><li>Acceso al esquema Oracle <strong><code>CURSONORMADM</code></strong> (entorno <code>ORACTEST</code>) con el usuario de aplicación <strong><code>CURSONORMWEB</code></strong>.</li><li>Proyecto base ya creado desde la plantilla UA (<code>PlantillaMVCCore.*</code>).</li><li><code>NuGet.Config</code> global apuntando al feed UA (ver <code>00-preparacion</code>).</li><li><code>dotnet user-secrets</code> configurado con <code>ConnectionStrings:oradb</code> en cada proyecto que vaya a abrir Oracle.</li><li>Node.js y <code>pnpm</code> para que la parte Vue compile (aunque las sesiones 7 y 8 <strong>no piden escribir Vue</strong>: la página <code>Home.vue</code> ya trae botones que llaman a la API para que se pueda probar todo desde Chrome).</li></ul></div><div class="info custom-block"><p class="custom-block-title">CONTEXTO — ejercicio transversal de sesiones 7 y 8</p><p>Durante estas dos sesiones el alumno trabajará sobre una entidad nueva, <strong><code>TRES_OBSERVACION_RESERVA</code></strong> (observaciones asociadas a una reserva, con texto multiidioma + <code>CODPER_AUTOR</code>). El SQL completo (tabla, vista <code>VRES_OBSERVACION_RESERVA</code> y paquete <code>PKG_RES_OBSERVACION_RESERVA</code> con <code>CREAR</code> y <code>ELIMINAR</code> por <code>ACTIVO=&#39;N&#39;</code>) <strong>se entrega ya hecho</strong>. La sesión 7 pide que el alumno cree DTOs y la API que devuelva 200 OK con datos hardcodeados; la sesión 8 pide que conecte el servicio al paquete y escriba un test simulado.</p></div>',9))])}const S=t(c,[["render",u]]);export{v as __pageData,S as default};
